import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"如意金箍棒","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/如意金箍棒.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/如意金箍棒.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/如意金箍棒.md"};function p(_,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"如意金箍棒",tabindex:"-1"},[s("如意金箍棒 "),e("a",{class:"header-anchor",href:"#如意金箍棒","aria-label":'Permalink to "如意金箍棒"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),o('<h1 id="如意金箍棒-1" tabindex="-1">如意金箍棒 <a class="header-anchor" href="#如意金箍棒-1" aria-label="Permalink to &quot;如意金箍棒&quot;">​</a></h1><p>如意金箍棒<br> 价格：A+10000<br> 分类：棍<br> 武器伤害：30L<br> 武器特性：【长柄】【法破】【重型武器】【余波】【幻灭】【攻击额外获得2个附加成功数】<br> 武器体积：3<br> 伤害类型：物理-钝击<br> 描述：出自东方玄幻世界，简称“金箍棒”和“如意棒”，又名“灵阳棒”或“天河定底神珍铁”以及“天河镇底神珍”。<br> 据传由太清道德天尊亲手炼制而成的仙家奇珍，是一种可以自由变化自身体积与质量的神奇武器，通常情况下呈现出暗金色泽，有着惊人的重量。当持有者握住时，表面缭绕着瑞气与霞光，挥舞时则转为煌煌大日般的闪耀金光。<br> 效果：<br> 【如意神兵】：<br> 如意金箍棒的体积每因“无限膨胀”增加1点，你就可以让武器伤害提高1L与1破甲，最多因此获得力量属性*1点武器伤害提升与破甲；仅限你在使用时，可以选择无需承受因“无限膨胀”带来武器体积提升导致的力量需求增加。</p><p>【沉重一击】：<br> 使用如意金箍棒攻击体积小于武器的目标时，你可以选择在攻击检定承受器械减值，并获得攻击附加成功，每承受2点器械减值就能获得1个额外攻击附加成功，最多获得等同传奇力量+传奇耐力/个附加成功。</p><p>【无限膨胀】：持有者花费一个移动动作，如意金箍棒将会急速膨胀，从虚无中凭空诞生出无尽质量，瞬间成长为擎天的巨大兵装，以挟山压卵之势向敌人碾去，变回来需要一个移动动作或直到该场景结束为止。此外，如意金箍棒也可以变成比绣花针略小的大小藏匿在身上，这一点没有时间限制，只需要自由动作即可切换大小。</p><p>按照你力量属性与体积，如意金箍棒的触及距离最大可放大至【力量属性*10+人物体积*2】米，如意金箍棒可以同时攻击近战触及距离内的所有敌对单位，可以在攻击时选择使目标进行反射豁免，而非正常防御。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
